mapper.insert:
INSERT INTO t_page_view_stat (id, page_type, page_key, day, cnt)
VALUES (#{id}, #{pageType}, #{pageKey}, #{day}, #{delta})
ON DUPLICATE KEY UPDATE cnt = cnt + #{delta}

mapper.select:
SELECT page_type AS pageType, page_key AS pageKey, SUM(cnt) AS cnt -- 时间窗口内 PV 总和 FROM t_page_view_stat WHERE day >= #{startDay}
AND page_type = #{pageType} -- 可选：仅统计指定类型页面
GROUP BY page_type, page_key ORDER BY cnt DESC
